{
    "level": "A1–A2",
    "intro": "W tym temacie nauczysz się odpowiadać na pytania po angielsku za pomocą <strong>krótkich</strong> i <strong>pełnych odpowiedzi</strong>.",
    "rules": [
        {
            "label": "KRÓTKIE ODPOWIEDZI",
            "color": "emerald",
            "text": "Najczęściej używamy <strong>yes/no + subject + auxiliary</strong>:",
            "example": "Do you like coffee? — Yes, I do. / No, I don't."
        },
        {
            "label": "PEŁNE ODPOWIEDZI",
            "color": "blue",
            "text": "Dla jasności możemy rozwinąć odpowiedź w całe zdanie:",
            "example": "Do you like coffee? — Yes, I like coffee."
        },
        {
            "label": "NIE TYLKO YES/NO",
            "color": "amber",
            "text": "Samo <strong>yes</strong> albo <strong>no</strong> bywa zbyt krótkie, zwłaszcza w bardziej formalnej sytuacji:",
            "example": "❌ Yes. → ✅ Yes, I do."
        }
    ]
}

{
    "title": "1. Typy odpowiedzi",
    "intro": "Na pytania po angielsku możemy odpowiadać na kilka sposobów:",
    "items": [
        {
            "label": "Tylko yes/no",
            "title": "Yes. / No.",
            "subtitle": "Bardzo krótko i dość nieformalnie"
        },
        {
            "label": "Krótkie odpowiedzi",
            "title": "Yes, I do. / No, she isn't.",
            "subtitle": "Najbardziej naturalne w codziennej rozmowie"
        },
        {
            "label": "Pełne odpowiedzi",
            "title": "Yes, I like coffee.",
            "subtitle": "Przydatne, gdy chcesz coś doprecyzować"
        }
    ]
}

{
    "title": "2. Krótkie odpowiedzi z DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "W Present Simple powtarzamy w odpowiedzi <strong>do</strong> albo <strong>does</strong>.",
            "examples": [
                {
                    "en": "Do you like coffee? — Yes, I do. / No, I don't.",
                    "ua": "Pytanie z <em>do</em> → odpowiedź z <em>do</em>."
                },
                {
                    "en": "Does she work here? — Yes, she does. / No, she doesn't.",
                    "ua": "Pytanie z <em>does</em> → odpowiedź z <em>does</em>."
                },
                {
                    "en": "Do they know? — Yes, they do. / No, they don't.",
                    "ua": "Powtarzamy czasownik pomocniczy, nie główny."
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "sky",
            "description": "W Past Simple dla wszystkich osób używamy <strong>did</strong>.",
            "examples": [
                {
                    "en": "Did you see the film? — Yes, I did. / No, I didn't.",
                    "ua": "Pytanie z <em>did</em> → odpowiedź z <em>did</em>."
                },
                {
                    "en": "Did she call you? — Yes, she did. / No, she didn't.",
                    "ua": "Ta sama zasada obowiązuje dla wszystkich osób."
                },
                {
                    "en": "Did they arrive? — Yes, they did. / No, they didn't.",
                    "ua": "Krótko i jasno."
                }
            ]
        },
        {
            "label": "Struktura",
            "color": "purple",
            "description": "Formuła krótkiej odpowiedzi jest prosta:",
            "examples": [
                {
                    "en": "Yes/No + subject + do/does/did (+ not)",
                    "ua": "Yes/No + podmiot + do/does/did (+ not)"
                }
            ],
            "note": "📌 W krótkiej odpowiedzi nie powtarzamy głównego czasownika."
        }
    ]
}

{
    "title": "3. Krótkie odpowiedzi z TO BE",
    "sections": [
        {
            "label": "Present Simple",
            "color": "blue",
            "description": "Z <strong>to be</strong> powtarzamy odpowiednią formę czasownika.",
            "examples": [
                {
                    "en": "Are you ready? — Yes, I am. / No, I'm not.",
                    "ua": "W odpowiedzi zachowujemy formę odpowiednią dla podmiotu."
                },
                {
                    "en": "Is she happy? — Yes, she is. / No, she isn't.",
                    "ua": "Pytanie z <em>is</em> → odpowiedź z <em>is</em>."
                },
                {
                    "en": "Are they at home? — Yes, they are. / No, they aren't.",
                    "ua": "Pytanie z <em>are</em> → odpowiedź z <em>are</em>."
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "amber",
            "description": "W czasie przeszłym używamy <strong>was</strong> i <strong>were</strong>.",
            "examples": [
                {
                    "en": "Were you tired? — Yes, I was. / No, I wasn't.",
                    "ua": "Pytanie z <em>were</em> → odpowiedź z <em>was</em> dla <em>I</em>."
                },
                {
                    "en": "Was it difficult? — Yes, it was. / No, it wasn't.",
                    "ua": "Pytanie z <em>was</em> → odpowiedź z <em>was</em>."
                },
                {
                    "en": "Were they happy? — Yes, they were. / No, they weren't.",
                    "ua": "Negacja zwykle brzmi naturalniej w skróconej formie."
                }
            ]
        },
        {
            "label": "Skrócenia",
            "color": "rose",
            "description": "W odpowiedziach przeczących najczęściej używamy form skróconych.",
            "examples": [
                {
                    "en": "No, I'm not.",
                    "ua": "To najczęstsza forma w zwykłej rozmowie."
                },
                {
                    "en": "No, she isn't. / No, she's not.",
                    "ua": "Obie wersje są poprawne."
                },
                {
                    "en": "No, they aren't.",
                    "ua": "Forma skrócona brzmi naturalnie i potocznie."
                }
            ],
            "note": "📌 W odpowiedziach twierdzących częściej używamy pełnej formy: <em>Yes, I am.</em>"
        }
    ]
}

{
    "title": "4. Krótkie odpowiedzi z modalnymi",
    "sections": [
        {
            "label": "CAN / COULD",
            "color": "emerald",
            "description": "Po pytaniu z modalem powtarzamy ten sam modal w odpowiedzi.",
            "examples": [
                {
                    "en": "Can you swim? — Yes, I can. / No, I can't.",
                    "ua": "Pytanie z <em>can</em> → odpowiedź z <em>can</em>."
                },
                {
                    "en": "Could she help? — Yes, she could. / No, she couldn't.",
                    "ua": "Pytanie z <em>could</em> → odpowiedź z <em>could</em>."
                }
            ]
        },
        {
            "label": "WILL / WOULD",
            "color": "sky",
            "description": "To samo dotyczy <strong>will</strong> i <strong>would</strong>.",
            "examples": [
                {
                    "en": "Will you come? — Yes, I will. / No, I won't.",
                    "ua": "Pytanie z <em>will</em> → odpowiedź z <em>will</em>."
                },
                {
                    "en": "Would you like some coffee? — Yes, I would. / No, I wouldn't.",
                    "ua": "Pytanie z <em>would</em> → odpowiedź z <em>would</em>."
                }
            ]
        },
        {
            "label": "SHOULD / MAY",
            "color": "purple",
            "description": "Inne modale działają według tej samej zasady.",
            "examples": [
                {
                    "en": "Should we go? — Yes, we should. / No, we shouldn't.",
                    "ua": "Powtarzamy modal z pytania."
                },
                {
                    "en": "May I ask? — Yes, you may. / No, you may not.",
                    "ua": "To bardziej formalny typ odpowiedzi."
                }
            ],
            "note": "📌 Struktura: <strong>Yes/No + subject + modal</strong>."
        }
    ]
}

{
    "title": "5. Krótkie odpowiedzi z HAVE/HAS",
    "sections": [
        {
            "label": "Present Perfect",
            "color": "amber",
            "description": "W Present Perfect powtarzamy <strong>have</strong> albo <strong>has</strong>.",
            "examples": [
                {
                    "en": "Have you seen it? — Yes, I have. / No, I haven't.",
                    "ua": "Pytanie z <em>have</em> → odpowiedź z <em>have</em>."
                },
                {
                    "en": "Has she finished? — Yes, she has. / No, she hasn't.",
                    "ua": "Pytanie z <em>has</em> → odpowiedź z <em>has</em>."
                }
            ]
        },
        {
            "label": "HAVE GOT",
            "color": "blue",
            "description": "W brytyjskiej konstrukcji <strong>have got</strong> także używamy <strong>have/has</strong>.",
            "examples": [
                {
                    "en": "Have you got a car? — Yes, I have. / No, I haven't.",
                    "ua": "W odpowiedzi powtarzamy <em>have</em>."
                },
                {
                    "en": "Has she got a dog? — Yes, she has. / No, she hasn't.",
                    "ua": "W odpowiedzi powtarzamy <em>has</em>."
                }
            ]
        },
        {
            "label": "Wersja amerykańska",
            "color": "rose",
            "description": "W amerykańskim angielskim z czasownikiem <strong>have</strong> często używamy <strong>do/does</strong>.",
            "examples": [
                {
                    "en": "Do you have a car? — Yes, I do. / No, I don't.",
                    "ua": "To typowa odpowiedź w wariancie amerykańskim."
                }
            ],
            "note": "📌 Warto zwracać uwagę, czy pytanie zostało zadane z <em>have</em>, czy z <em>do/does</em>."
        }
    ]
}

{
    "title": "6. Krótkie odpowiedzi z innymi czasami",
    "sections": [
        {
            "label": "Present Continuous",
            "color": "emerald",
            "description": "W Present Continuous odpowiadamy formą <strong>am/is/are</strong>.",
            "examples": [
                {
                    "en": "Are you working? — Yes, I am. / No, I'm not.",
                    "ua": "Powtarzamy ten sam czasownik pomocniczy."
                },
                {
                    "en": "Is she coming? — Yes, she is. / No, she isn't.",
                    "ua": "To be wraca w odpowiedzi."
                }
            ]
        },
        {
            "label": "Past Continuous",
            "color": "sky",
            "description": "W Past Continuous używamy <strong>was</strong> albo <strong>were</strong>.",
            "examples": [
                {
                    "en": "Were you sleeping? — Yes, I was. / No, I wasn't.",
                    "ua": "Powtarzamy <em>was/were</em>."
                },
                {
                    "en": "Was she studying? — Yes, she was. / No, she wasn't.",
                    "ua": "Krótka odpowiedź jest najnaturalniejsza."
                }
            ]
        },
        {
            "label": "Zasada ogólna",
            "color": "purple",
            "description": "W krótkiej odpowiedzi zawsze wracamy do tego samego czasownika pomocniczego, który był w pytaniu.",
            "examples": [
                {
                    "en": "do → do / does / did",
                    "ua": "Powtarzamy <em>do</em>, <em>does</em> albo <em>did</em>."
                },
                {
                    "en": "be → am / is / are / was / were",
                    "ua": "Powtarzamy odpowiednią formę <em>to be</em>."
                },
                {
                    "en": "modal → can / will / should ...",
                    "ua": "Powtarzamy modal z pytania."
                }
            ],
            "note": "📌 Krótka odpowiedź = <strong>Yes/No + subject + auxiliary</strong>."
        }
    ]
}

{
    "title": "7. Pełne odpowiedzi",
    "sections": [
        {
            "label": "Kiedy używać",
            "color": "blue",
            "description": "Pełna odpowiedź przydaje się, gdy chcesz coś doprecyzować albo dodać więcej informacji.",
            "examples": [
                {
                    "en": "Do you like coffee? — Yes, I like coffee very much.",
                    "ua": "Dodajemy szczegół albo opinię."
                },
                {
                    "en": "Did she call? — Yes, she called me this morning.",
                    "ua": "Możemy dopowiedzieć kiedy albo jak."
                },
                {
                    "en": "Will they come? — No, they won't. They're busy.",
                    "ua": "Pełna odpowiedź może zawierać wyjaśnienie."
                }
            ]
        },
        {
            "label": "Struktura",
            "color": "amber",
            "description": "W pełnej odpowiedzi powtarzamy treść pytania w formie zdania twierdzącego albo przeczącego.",
            "examples": [
                {
                    "en": "Do you work here? — Yes, I work here.",
                    "ua": "Powtarzamy całe zdanie."
                },
                {
                    "en": "Is she a teacher? — Yes, she is a teacher.",
                    "ua": "To bardziej wyraźna odpowiedź niż sama krótka forma."
                },
                {
                    "en": "Can you swim? — No, I can't swim.",
                    "ua": "Pełna odpowiedź wyraźnie pokazuje sens."
                }
            ]
        },
        {
            "label": "Krótka + pełna odpowiedź",
            "color": "emerald",
            "description": "Bardzo naturalnie brzmi połączenie krótkiej odpowiedzi z dodatkową informacją.",
            "examples": [
                {
                    "en": "Do you speak English? — Yes, I do. I also speak French.",
                    "ua": "Krótka odpowiedź + dodatkowy szczegół."
                },
                {
                    "en": "Did you like the film? — No, I didn't. It was too long.",
                    "ua": "To częsty wzór w codziennej rozmowie."
                }
            ],
            "note": "📌 Krótka odpowiedź + rozwinięcie brzmi naturalnie i jasno."
        }
    ]
}

{
    "title": "8. Odpowiedzi na pytania Wh",
    "sections": [
        {
            "label": "Konkretna informacja",
            "color": "purple",
            "description": "Na pytania Wh nie odpowiadamy zwykle <strong>yes/no</strong>, tylko podajemy potrzebną informację.",
            "examples": [
                {
                    "en": "What do you like? — I like coffee.",
                    "ua": "Odpowiadamy na pytanie <em>co?</em>"
                },
                {
                    "en": "Where do you live? — I live in Kyiv.",
                    "ua": "Odpowiadamy na pytanie <em>gdzie?</em>"
                },
                {
                    "en": "When did you arrive? — I arrived yesterday.",
                    "ua": "Odpowiadamy na pytanie <em>kiedy?</em>"
                }
            ]
        },
        {
            "label": "Krótko albo pełnym zdaniem",
            "color": "sky",
            "description": "Na pytanie Wh można odpowiedzieć bardzo krótko albo pełnym zdaniem.",
            "examples": [
                {
                    "en": "Where are you from? — From Ukraine. / I'm from Ukraine.",
                    "ua": "Obie formy są poprawne."
                },
                {
                    "en": "What time is it? — Five o'clock. / It's five o'clock.",
                    "ua": "Krótka i pełna odpowiedź są możliwe."
                },
                {
                    "en": "Who is she? — My sister. / She is my sister.",
                    "ua": "Dwie naturalne wersje odpowiedzi."
                }
            ],
            "note": "📌 W pytaniach Wh najważniejsze jest przekazanie właściwej informacji."
        }
    ]
}

{
    "title": "9. Szybka tabela",
    "intro": "Jak wyglądają krótkie odpowiedzi z różnymi typami czasowników:",
    "rows": [
        {
            "en": "DO/DOES/DID",
            "ua": "Czasy proste",
            "note": "Yes, I do. / No, she doesn't. / Yes, they did."
        },
        {
            "en": "TO BE",
            "ua": "Czasownik to be",
            "note": "Yes, I am. / No, he isn't. / Yes, they were."
        },
        {
            "en": "MODALS",
            "ua": "Czasowniki modalne",
            "note": "Yes, I can. / No, she won't."
        },
        {
            "en": "HAVE/HAS",
            "ua": "Perfect i have got",
            "note": "Yes, I have. / No, she hasn't."
        },
        {
            "en": "CONTINUOUS",
            "ua": "Czasy ciągłe",
            "note": "Yes, I am. / No, they weren't."
        }
    ],
    "warning": "📌 W krótkiej odpowiedzi zawsze powtarzamy <strong>czasownik pomocniczy z pytania</strong>."
}

{
    "title": "10. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Samo yes/no bez czasownika pomocniczego w sytuacji, gdy potrzebna jest pełniejsza odpowiedź.",
            "wrong": "❌ Do you like it? — Yes.",
            "right": "✅ <span class=\"font-mono\">Do you like it? — Yes, I do.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Powtarzanie głównego czasownika zamiast czasownika pomocniczego.",
            "wrong": "❌ Do you like it? — Yes, I like.",
            "right": "✅ <span class=\"font-mono\">Do you like it? — Yes, I do.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zły czasownik pomocniczy w odpowiedzi.",
            "wrong": "❌ Can you swim? — Yes, I do.",
            "right": "✅ <span class=\"font-mono\">Can you swim? — Yes, I can.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Odpowiedź yes/no na pytanie Wh bez konkretnej informacji.",
            "wrong": "❌ Where do you live? — Yes.",
            "right": "✅ <span class=\"font-mono\">Where do you live? — In Kyiv.</span>"
        }
    ]
}

{
    "title": "12. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz poprawną odpowiedź",
    "select_intro": "Wybierz właściwą krótką odpowiedź.",
    "selects": [
        {
            "label": "Q: Do you like coffee? A: (Yes, I do. / Yes, I like. / Yes.)",
            "prompt": "Która odpowiedź jest poprawna?"
        },
        {
            "label": "Q: Is she happy? A: (Yes, she is. / Yes, she does. / Yes, happy.)",
            "prompt": "Która odpowiedź jest poprawna?"
        },
        {
            "label": "Q: Can you swim? A: (Yes, I can. / Yes, I do. / Yes, I swim.)",
            "prompt": "Która odpowiedź jest poprawna?"
        },
        {
            "label": "Q: Did they arrive? A: (No, they didn't. / No, they don't. / No, arrived.)",
            "prompt": "Która odpowiedź jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Ćwiczenie 2. Podaj krótką odpowiedź",
    "input_intro": "Uzupełnij poprawną krótką odpowiedź.",
    "inputs": [
        {
            "before": "Q: Do you speak English? A: Yes, ",
            "after": "."
        },
        {
            "before": "Q: Is she a teacher? A: No, ",
            "after": "."
        },
        {
            "before": "Q: Can they help? A: Yes, ",
            "after": "."
        },
        {
            "before": "Q: Have you seen it? A: No, ",
            "after": "."
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w odpowiedzi.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Q: Do you like it? A: Yes, I like.",
            "example_target": "Q: Do you like it? A: Yes, I do."
        },
        {
            "original": "1. Q: Can you help? A: Yes, I do.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Q: Is he ready? A: No, he doesn't.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Q: Where do you live? A: Yes, in Warsaw.",
            "placeholder": "Popraw odpowiedź"
        }
    ]
}

